import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 盛華器 } from '../bujian/sanmaya.js';
import { 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛華 = (bi) => 菩薩坐身(bi, {
    髻: '天髻',
    冠: '無',
    嚴先: true,
    臂(bi, 筆) {
        const { M, Qk, S, 骨, 衣, 細, 陰, 陽 } = 筆;
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.0); });
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.1], [-6.4, 41.0], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.4, 肘帽: true })));
        骨(() => 陰(() => 前臂(bi, 筆, [13.7, 40.1], [6.4, 41.0], { 寬根: 2.5, 寬梢: 1.9, 弓: -0.4, 肘帽: true })));
        // 盛華之盤先落（盤中未敷蓮華——「盛」字要緊）
        盛華器(bi, 0, 38.2, 0.85);
        // 右掌承盤底，左掌添盤緣
        衣(() => {
            M(-5.9, 40.4);
            Qk(-4.4, 41.3, -2.8, 40.7);
            S();
            M(-5.6, 41.1);
            Qk(-4.4, 41.8, -3.2, 41.3);
            S();
            M(5.9, 39.9);
            Qk(4.4, 40.7, 2.8, 40.1);
            S();
            M(5.6, 40.6);
            Qk(4.4, 41.2, 3.2, 40.7);
            S();
            細(() => {
                for (const t of [0, 1, 2]) {
                    M(-5.5 + t * 1.0, 40.15 - t * 0.12);
                    Qk(-5.2 + t * 1.0, 39.8 - t * 0.12, -4.8 + t * 1.0, 39.65 - t * 0.12);
                    S();
                    M(5.5 - t * 1.0, 39.65 - t * 0.1);
                    Qk(5.2 - t * 1.0, 39.3 - t * 0.1, 4.8 - t * 1.0, 39.15 - t * 0.1);
                    S();
                }
            });
        });
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-7.4, 39.7, -6.7, 40.6, -7.4, 41.7], [-6.5, 39.5, -5.8, 40.4, -6.5, 41.5]], [-6.7, 40.5]);
            腕釧(bi, [[7.4, 39.2, 6.7, 40.1, 7.4, 41.2], [6.5, 39.0, 5.8, 39.9, 6.5, 41.0]], [6.7, 40.0]);
        });
    },
});
